using LifeOS.Companion.Core.Models;using LifeOS.Companion.Core.Storage;
namespace LifeOS.Companion.Views;
public sealed class ConflictsPage:ContentPage
{readonly ICompanionStore _store;readonly VerticalStackLayout _list=new();public ConflictsPage(ICompanionStore store){_store=store;Title="Conflicts";Content=new ScrollView{Content=new VerticalStackLayout{Padding=16,Spacing=12,Children={new Label{Text="Explicit conflict resolution",FontSize=24,FontAttributes=FontAttributes.Bold},new Label{Text="Changed content is never overwritten silently. Every completed resolution is audited."},_list}}};}protected override async void OnAppearing(){base.OnAppearing();await Refresh();}async Task Refresh(){_list.Children.Clear();foreach(var c in await _store.GetConflictsAsync()){var status=new Label{Text=c.Resolved?$"Resolved: {c.Resolution}":"UNRESOLVED"};var buttons=new HorizontalStackLayout{Spacing=6};foreach(var choice in new[]{ConflictResolutionChoice.KeepPhoneDraft,ConflictResolutionChoice.KeepDesktopVersion,ConflictResolutionChoice.CreateSeparateReviewItem,ConflictResolutionChoice.Cancel}){var b=new Button{Text=choice.ToString(),IsEnabled=!c.Resolved};b.Clicked+=async(_,__)=>{await _store.ResolveConflictAsync(c.ConflictId,choice);await Refresh();};buttons.Add(b);}_list.Add(new Border{Padding=12,Content=new VerticalStackLayout{Children={new Label{Text=$"Capture {c.CaptureId[..Math.Min(8,c.CaptureId.Length)]}",FontAttributes=FontAttributes.Bold},status,buttons}}});}}}
